namespace sv_4281a37f8a344b18a06b9ef7b4f7b4b0.Services;

public record Channel(int Id, string Name, string Description, int UnreadCount);
public record Message(int Id, int ChannelId, string Author, string Content, DateTime SentAt, int? ReplyToId, List<Reaction> Reactions);
public record Reaction(string Emoji, List<string> Users);
public record ThreadSummary(int RootMessageId, int ReplyCount, DateTime LastReplyAt);

public interface IChatService
{
    Task<List<Channel>> GetChannelsAsync();
    Task<List<Message>> GetMessagesAsync(int channelId, int skip, int take);
    Task<Message> SendMessageAsync(int channelId, string content, int? replyToId);
    Task<List<Message>> GetThreadAsync(int rootMessageId);
    Task AddReactionAsync(int messageId, string emoji);
    Task MarkChannelReadAsync(int channelId);
}

.message-input {
    display: flex;
    gap: 8px;
    padding: 12px 16px;
    border-top: 1px solid #e0e0e0;
    background: #fff;
}

.message-input-textarea {
    flex: 1;
    resize: none;
    border: 1px solid #ccc;
    border-radius: 6px;
    padding: 8px 12px;
    font-size: 14px;
    font-family: inherit;
    min-height: 40px;
    max-height: 120px;
    outline: none;
}

.message-input-textarea:focus {
    border-color: #1264a3;
    box-shadow: 0 0 0 1px #1264a3;
}

.message-input-button {
    align-self: flex-end;
    background: #007a5a;
    color: #fff;
    border: none;
    border-radius: 6px;
    padding: 8px 16px;
    font-size: 14px;
    font-weight: 600;
    cursor: pointer;
    white-space: nowrap;
}

.message-input-button:hover:not(:disabled) {
    background: #005e44;
}

.message-input-button:disabled {
    opacity: 0.5;
    cursor: default;
}

@if (Visible)
{
    <div class="emoji-picker">
        @foreach (var emoji in Emojis)
        {
            <button class="emoji-option" @onclick="() => SelectEmoji(emoji)" title="@emoji">
                @emoji
            </button>
        }
    </div>
}

@code {
    [Parameter] public bool Visible { get; set; }
    [Parameter] public EventCallback<string> OnEmojiSelected { get; set; }

    private static readonly string[] Emojis = ["👍", "❤️", "😂", "🎉", "😮", "🔥"];

    private async Task SelectEmoji(string emoji)
    {
        await OnEmojiSelected.InvokeAsync(emoji);
    }
}

.emoji-picker {
    display: flex;
    gap: 2px;
    background: #fff;
    border: 1px solid #ddd;
    border-radius: 8px;
    padding: 4px;
    box-shadow: 0 2px 8px rgba(0,0,0,0.15);
    position: absolute;
    bottom: 100%;
    right: 0;
    margin-bottom: 4px;
    z-index: 10;
}

.emoji-option {
    background: none;
    border: none;
    font-size: 18px;
    padding: 4px 6px;
    border-radius: 4px;
    cursor: pointer;
    line-height: 1;
}

.emoji-option:hover {
    background: #f0f0f0;
}

.message-bubble {
    position: relative;
    padding: 6px 16px;
    border-radius: 4px;
    transition: background 0.15s;
}

.message-bubble:hover {
    background: #f8f8f8;
}

.message-bubble.highlighted {
    background: #fff9e6;
    border-left: 3px solid #e8a800;
    padding-left: 13px;
}

.message-header {
    display: flex;
    align-items: baseline;
    gap: 8px;
    margin-bottom: 2px;
}

.message-author {
    font-weight: 700;
    font-size: 15px;
    color: #1d1c1d;
}

.message-time {
    font-size: 12px;
    color: #616061;
}

.message-content {
    font-size: 15px;
    line-height: 1.46;
    color: #1d1c1d;
    word-break: break-word;
}

.reaction-row {
    display: flex;
    flex-wrap: wrap;
    gap: 4px;
    margin-top: 4px;
}

.reaction-badge {
    display: inline-flex;
    align-items: center;
    gap: 4px;
    background: #f0f4ff;
    border: 1px solid #c8d6e5;
    border-radius: 12px;
    padding: 2px 8px;
    font-size: 13px;
    cursor: pointer;
    line-height: 1.4;
}

.reaction-badge:hover {
    background: #dde6f5;
}

.thread-link {
    background: none;
    border: none;
    color: #1264a3;
    font-size: 13px;
    font-weight: 600;
    cursor: pointer;
    padding: 2px 0;
    margin-top: 2px;
}

.thread-link:hover {
    text-decoration: underline;
}

.message-actions {
    position: absolute;
    top: -12px;
    right: 8px;
    display: flex;
    gap: 2px;
    background: #fff;
    border: 1px solid #ddd;
    border-radius: 6px;
    padding: 2px;
    box-shadow: 0 1px 4px rgba(0,0,0,0.1);
}

.action-btn {
    background: none;
    border: none;
    font-size: 16px;
    padding: 4px 6px;
    border-radius: 4px;
    cursor: pointer;
    line-height: 1;
}

.action-btn:hover {
    background: #f0f0f0;
}

.react-action-wrapper {
    position: relative;
}

.channel-item {
    display: block;
    width: 100%;
    text-align: left;
    background: none;
    border: none;
    padding: 8px 16px;
    cursor: pointer;
    border-radius: 6px;
    margin: 1px 8px;
    transition: background 0.15s;
}

.channel-item:hover {
    background: rgba(255,255,255,0.1);
}

.channel-item.active {
    background: #1264a3;
    color: #fff;
}

.channel-item-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
}

.channel-name {
    font-size: 15px;
    font-weight: 400;
    color: rgba(255,255,255,0.9);
}

.channel-item.active .channel-name {
    color: #fff;
    font-weight: 700;
}

.channel-desc {
    font-size: 12px;
    color: rgba(255,255,255,0.55);
    margin-top: 1px;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

.channel-item.active .channel-desc {
    color: rgba(255,255,255,0.8);
}

.unread-badge {
    background: #e01e5a;
    color: #fff;
    font-size: 11px;
    font-weight: 700;
    padding: 1px 6px;
    border-radius: 10px;
    min-width: 18px;
    text-align: center;
    line-height: 1.4;
}

.channel-sidebar {
    display: flex;
    flex-direction: column;
    background: #3f0e40;
    color: #fff;
    height: 100%;
    overflow: hidden;
}

.sidebar-header {
    padding: 16px 16px 8px;
    border-bottom: 1px solid rgba(255,255,255,0.1);
}

.sidebar-title {
    font-size: 18px;
    font-weight: 700;
    margin: 0;
}

.channel-list {
    flex: 1;
    overflow-y: auto;
    padding: 8px 0;
}

.message-list {
    flex: 1;
    overflow-y: auto;
    padding: 8px 0;
    display: flex;
    flex-direction: column;
    gap: 2px;
}

.loading-indicator {
    text-align: center;
    padding: 12px;
    color: #888;
    font-size: 13px;
}

.empty-state {
    text-align: center;
    padding: 40px 16px;
    color: #888;
    font-size: 15px;
}

.thread-panel {
    display: flex;
    flex-direction: column;
    height: 100%;
    background: #fff;
    border-left: 1px solid #ddd;
}

.thread-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 12px 16px;
    border-bottom: 1px solid #e0e0e0;
}

.thread-title {
    font-size: 16px;
    font-weight: 700;
    margin: 0;
    color: #1d1c1d;
}

.thread-close {
    background: none;
    border: none;
    font-size: 18px;
    color: #616061;
    cursor: pointer;
    padding: 4px 8px;
    border-radius: 4px;
    line-height: 1;
}

.thread-close:hover {
    background: #f0f0f0;
    color: #1d1c1d;
}

.thread-root-quote {
    padding: 8px 0;
    border-bottom: 1px solid #e0e0e0;
}

.thread-divider {
    display: flex;
    align-items: center;
    padding: 8px 16px;
    font-size: 12px;
    color: #888;
    gap: 8px;
}

.thread-divider::before,
.thread-divider::after {
    content: '';
    flex: 1;
    height: 1px;
    background: #e0e0e0;
}

.thread-replies {
    flex: 1;
    overflow-y: auto;
    padding: 4px 0;
}

.message-area {
    display: flex;
    flex-direction: column;
    height: 100%;
    background: #fff;
}

.message-area-header {
    display: flex;
    align-items: baseline;
    gap: 12px;
    padding: 12px 16px;
    border-bottom: 1px solid #e0e0e0;
    flex-shrink: 0;
}

.channel-title {
    font-size: 18px;
    font-weight: 700;
    margin: 0;
    color: #1d1c1d;
    white-space: nowrap;
}

.channel-description {
    font-size: 13px;
    color: #616061;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

