{"path": "/tmp/sv-4281a37f8a344b18a06b9ef7b4f7b4b0/Components/Chat/MessageInput.razor", "file_text": "<div class="message-input">
    <textarea class="message-input-textarea"
              placeholder="@Placeholder"
              @bind="messageText"
              @bind:event="oninput"
              @onkeydown="HandleKeyDown"></textarea>
    <button class="message-input-button" @onclick="HandleSend" disabled="@string.IsNullOrWhiteSpace(messageText)">
        @ButtonLabel
    </button>
</div>

@code {
    [Parameter] public string Placeholder { get; set; } = "Type a message...";
    [Parameter] public string ButtonLabel { get; set; } = "Send";
    [Parameter] public EventCallback<string> OnSend { get; set; }

    private string messageText = string.Empty;

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await HandleSend();
        }
    }

    private async Task HandleSend()
    {
        var text = messageText.Trim();
        if (string.IsNullOrWhiteSpace(text)) return;

        messageText = string.Empty;
        await OnSend.InvokeAsync(text);
    }
}
"}

