.message-bubble {
    position: relative;
    padding: 6px 16px;
    border-radius: 4px;
    transition: background 0.15s;
}

.message-bubble:hover {
    background: #f8f8f8;
}

.message-bubble.highlighted {
    background: #fff9e6;
    border-left: 3px solid #e8a800;
    padding-left: 13px;
}

.message-header {
    display: flex;
    align-items: baseline;
    gap: 8px;
    margin-bottom: 2px;
}

.message-author {
    font-weight: 700;
    font-size: 15px;
    color: #1d1c1d;
}

.message-time {
    font-size: 12px;
    color: #616061;
}

.message-content {
    font-size: 15px;
    line-height: 1.46;
    color: #1d1c1d;
    word-break: break-word;
}

.reaction-row {
    display: flex;
    flex-wrap: wrap;
    gap: 4px;
    margin-top: 4px;
}

.reaction-badge {
    display: inline-flex;
    align-items: center;
    gap: 4px;
    background: #f0f4ff;
    border: 1px solid #c8d6e5;
    border-radius: 12px;
    padding: 2px 8px;
    font-size: 13px;
    cursor: pointer;
    line-height: 1.4;
}

.reaction-badge:hover {
    background: #dde6f5;
}

.thread-link {
    background: none;
    border: none;
    color: #1264a3;
    font-size: 13px;
    font-weight: 600;
    cursor: pointer;
    padding: 2px 0;
    margin-top: 2px;
}

.thread-link:hover {
    text-decoration: underline;
}

.message-actions {
    position: absolute;
    top: -12px;
    right: 8px;
    display: flex;
    gap: 2px;
    background: #fff;
    border: 1px solid #ddd;
    border-radius: 6px;
    padding: 2px;
    box-shadow: 0 1px 4px rgba(0,0,0,0.1);
}

.action-btn {
    background: none;
    border: none;
    font-size: 16px;
    padding: 4px 6px;
    border-radius: 4px;
    cursor: pointer;
    line-height: 1;
}

.action-btn:hover {
    background: #f0f0f0;
}

.react-action-wrapper {
    position: relative;
}

