arguments.file_text:
namespace sv_4281a37f8a344b18a06b9ef7b4f7b4b0.Services;

public record Channel(int Id, string Name, string Description, int UnreadCount);
public record Message(int Id, int ChannelId, string Author, string Content, DateTime SentAt, int? ReplyToId, List<Reaction> Reactions);
public record Reaction(string Emoji, List<string> Users);
public record ThreadSummary(int RootMessageId, int ReplyCount, DateTime LastReplyAt);

public interface IChatService
{
    Task<List<Channel>> GetChannelsAsync();
    Task<List<Message>> GetMessagesAsync(int channelId, int skip, int take);
    Task<Message> SendMessageAsync(int channelId, string content, int? replyToId);
    Task<List<Message>> GetThreadAsync(int rootMessageId);
    Task AddReactionAsync(int messageId, string emoji);
    Task MarkChannelReadAsync(int channelId);
}

@page "/chat"
@using sv_4281a37f8a344b18a06b9ef7b4f7b4b0.Services
@rendermode InteractiveServer
@inject IChatService ChatService
@inject IJSRuntime JS
@implements IAsyncDisposable

<PageTitle>Chat</PageTitle>

<div class="chat-layout">
    <div class="chat-sidebar">
        <ChannelSidebar Channels="channels"
                        SelectedChannelId="selectedChannelId"
                        OnChannelSelected="SelectChannel" />
    </div>

    <div class="chat-main @(threadRootMessage is null ? "full-width" : "")">
        @if (selectedChannel is not null)
        {
            <MessageArea ChannelName="@selectedChannel.Name"
                         ChannelDescription="@selectedChannel.Description"
                         Messages="messages"
                         ThreadSummaries="threadSummaries"
                         IsLoadingMore="isLoadingMore"
                         HasMoreMessages="hasMoreMessages"
                         OnOpenThread="OpenThread"
                         OnReact="HandleReaction"
                         OnLoadMore="LoadMoreMessages"
                         OnSendMessage="SendMessage" />
        }
        else
        {
            <div class="chat-placeholder">
                <p>Select a channel to start chatting</p>
            </div>
        }
    </div>

    @if (threadRootMessage is not null)
    {
        <div class="chat-thread">
            <ThreadPanel RootMessage="threadRootMessage"
                         Replies="threadReplies"
                         OnClose="CloseThread"
                         OnSendReply="SendThreadReply" />
        </div>
    }
</div>

@code {
    private const int PageSize = 30;

    private List<Channel> channels = [];
    private Channel? selectedChannel;
    private int selectedChannelId;

    private List<Message> messages = [];
    private Dictionary<int, ThreadSummary> threadSummaries = [];
    private bool isLoadingMore;
    private bool hasMoreMessages = true;

    private Message? threadRootMessage;
    private List<Message> threadReplies = [];

    private IJSObjectReference? scrollModule;
    private DotNetObjectReference<Chat>? dotNetRef;

    protected override async Task OnInitializedAsync()
    {
        channels = await ChatService.GetChannelsAsync();

        if (channels.Count > 0)
        {
            await SelectChannel(channels[0].Id);
        }
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            dotNetRef = DotNetObjectReference.Create(this);
            scrollModule = await JS.InvokeAsync<IJSObjectReference>(
                "import", "./Components/Pages/Chat.razor.js");
            await scrollModule.InvokeVoidAsync("observeScroll", ".message-list", dotNetRef);
        }
    }

    [JSInvokable]
    public async Task OnScrolledToTop()
    {
        if (!isLoadingMore && hasMoreMessages)
        {
            await LoadMoreMessages();
            StateHasChanged();
        }
    }

    private async Task SelectChannel(int channelId)
    {
        selectedChannelId = channelId;
        selectedChannel = channels.Find(c => c.Id == channelId);
        messages = [];
        threadSummaries = [];
        hasMoreMessages = true;
        threadRootMessage = null;
        threadReplies = [];

        messages = await ChatService.GetMessagesAsync(channelId, 0, PageSize);
        hasMoreMessages = messages.Count >= PageSize;

        await ChatService.MarkChannelReadAsync(channelId);

        // Refresh channels to update unread counts
        channels = await ChatService.GetChannelsAsync();

        BuildThreadSummaries();
    }

    private async Task LoadMoreMessages()
    {
        if (selectedChannel is null || isLoadingMore) return;

        isLoadingMore = true;

        var olderMessages = await ChatService.GetMessagesAsync(
            selectedChannel.Id, messages.Count, PageSize);

        if (olderMessages.Count < PageSize)
        {
            hasMoreMessages = false;
        }

        messages.InsertRange(0, olderMessages);
        BuildThreadSummaries();

        isLoadingMore = false;
    }

    private async Task SendMessage(string content)
    {
        if (selectedChannel is null) return;

        var newMessage = await ChatService.SendMessageAsync(
            selectedChannel.Id, content, null);
        messages.Add(newMessage);
    }

    private async Task OpenThread(int messageId)
    {
        threadRootMessage = messages.Find(m => m.Id == messageId);
        if (threadRootMessage is null) return;

        var allThreadMessages = await ChatService.GetThreadAsync(messageId);
        threadReplies = allThreadMessages
            .Where(m => m.Id != messageId)
            .ToList();
    }

    private void CloseThread()
    {
        threadRootMessage = null;
        threadReplies = [];
    }

    private async Task SendThreadReply(string content)
    {
        if (selectedChannel is null || threadRootMessage is null) return;

        var reply = await ChatService.SendMessageAsync(
            selectedChannel.Id, content, threadRootMessage.Id);
        threadReplies.Add(reply);

        // Update thread summary in main view
