        channels = await ChatService.GetChannelsAsync();

        BuildThreadSummaries();
    }

    private async Task LoadMoreMessages()
    {
        if (selectedChannel is null || isLoadingMore) return;

        isLoadingMore = true;

        var olderMessages = await ChatService.GetMessagesAsync(
            selectedChannel.Id, messages.Count, PageSize);

        if (olderMessages.Count < PageSize)
        {
            hasMoreMessages = false;
        }

        messages.InsertRange(0, olderMessages);
        BuildThreadSummaries();

        isLoadingMore = false;
    }

    private async Task SendMessage(string content)
    {
        if (selectedChannel is null) return;

        var newMessage = await ChatService.SendMessageAsync(
            selectedChannel.Id, content, null);
        messages.Add(newMessage);
    }

    private async Task OpenThread(int messageId)
    {
        threadRootMessage = messages.Find(m => m.Id == messageId);
        if (threadRootMessage is null) return;

        var allThreadMessages = await ChatService.GetThreadAsync(messageId);
        threadReplies = allThreadMessages
            .Where(m => m.Id != messageId)
            .ToList();
    }

    private void CloseThread()
    {
        threadRootMessage = null;
        threadReplies = [];
    }

    private async Task SendThreadReply(string content)
    {
        if (selectedChannel is null || threadRootMessage is null) return;

        var reply = await ChatService.SendMessageAsync(
            selectedChannel.Id, content, threadRootMessage.Id);
        threadReplies.Add(reply);

        // Update thread summary in main view
        if (threadSummaries.ContainsKey(threadRootMessage.Id))
        {
            threadSummaries[threadRootMessage.Id] = threadSummaries[threadRootMessage.Id]
                with { ReplyCount = threadReplies.Count, LastReplyAt = reply.SentAt };
        }
        else
        {
            threadSummaries[threadRootMessage.Id] = new ThreadSummary(
                threadRootMessage.Id, threadReplies.Count, reply.SentAt);
        }
    }

    private async Task HandleReaction((int MessageId, string Emoji) args)
    {
        await ChatService.AddReactionAsync(args.MessageId, args.Emoji);

        // Refresh messages to show updated reactions
        if (selectedChannel is not null)
        {
            messages = await ChatService.GetMessagesAsync(
                selectedChannel.Id, 0, messages.Count);
        }
    }

    private void BuildThreadSummaries()
    {
        threadSummaries = messages
            .Where(m => m.ReplyToId is not null)
            .GroupBy(m => m.ReplyToId!.Value)
            .ToDictionary(
                g => g.Key,
                g => new ThreadSummary(g.Key, g.Count(), g.Max(m => m.SentAt)));
    }

    public async ValueTask DisposeAsync()
    {
        if (scrollModule is not null)
        {
            try
            {
                await scrollModule.InvokeVoidAsync("dispose");
                await scrollModule.DisposeAsync();
            }
            catch (JSDisconnectedException) { }
        }
        dotNetRef?.Dispose();
    }
}

