let observer = null;
let scrollEl = null;

export function observeScroll(selector, dotNetRef) {
    scrollEl = document.querySelector(selector);
    if (!scrollEl) return;

    scrollEl.addEventListener('scroll', () => {
        if (scrollEl.scrollTop === 0) {
            dotNetRef.invokeMethodAsync('OnScrolledToTop');
        }
    });
}

export function dispose() {
    scrollEl = null;
}

